from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_login import login_required, current_user

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    account_type = db.Column(db.String(50), default='basic')
    credits = db.Column(db.Integer, default=0)
    referral_code = db.Column(db.String(50))
    verified_status = db.Column(db.Boolean, default=False)

@app.route('/update_profile', methods=['POST'])
@login_required
def update_profile():
    data = request.get_json()
    allowed_fields = ['email', 'username', 'account_type', 'credits', 'referral_code', 'verified_status']
    
    for field in data:
        if field not in allowed_fields:
            return jsonify({'error': f'Invalid field: {field}'}), 400
    
    update_data = {key: value for key, value in data.items() if key in allowed_fields}
    
    current_user.update(**update_data)
    db.session.commit()
    
    return jsonify(current_user.to_dict()), 200